<?php $fp=@stream_socket_client("tcp://smtp.gmail.com:587",$errno,$errstr,10); if(!$fp){var_dump(false,$errno,$errstr); exit;} stream_set_timeout($fp,10); fgets($fp); fwrite($fp,"EHLO localhost\r\n"); while(($line=fgets($fp))!==false){ if(strpos($line,"250 ")===0) break; } fwrite($fp,"STARTTLS\r\n"); $resp=fgets($fp); $tls=@stream_socket_enable_crypto($fp,true,STREAM_CRYPTO_METHOD_TLS_CLIENT); var_dump((bool)$fp,$errno,$errstr,trim((string)$resp),$tls); fclose($fp);
